mapper.select:
SELECT COUNT(*) FROM reservations


        AND start_time >= #{startTime}


        AND end_time <= #{endTime}


        AND status = #{status}

SELECT COUNT(DISTINCT user_id) FROM reservations


        AND start_time >= #{startTime}


        AND end_time <= #{endTime}

SELECT COUNT(DISTINCT room_id) FROM reservations


        AND start_time >= #{startTime}


        AND end_time <= #{endTime}

select *
from rooms
where id NOT IN (
    select room_id
    from reservations
    where start_time < #{endTime}
      AND end_time > #{startTime}
      AND NOT (
          sign_start_time IS NULL
          AND TIMESTAMPDIFF(MINUTE, start_time, NOW()) > #{graceMinutes}
      )
      AND status = 'approved'
)
AND longitude IS NOT NULL AND latitude IS NOT NULL  

    AND room_type_id = #{roomTypeId}

AND status != 0

SELECT re.id, re.user_id, re.room_id, re.title, re.purpose, re.start_time, re.end_time, re.attendees, re.status, re.remarks, re.reviewer_id, re.review_time, re.review_remarks, re.created_at, re.updated_at, re.sign_start_time, re.sign_end_time, rooms.name as room_name, u.username as username, u.phone as phone FROM reservations re LEFT JOIN rooms on re.room_id = rooms.id LEFT JOIN users u on re.user_id = u.id
and re.user_id = #{userId}
and re.status = #{status}
and re.start_time >= #{startTime}
and re.end_time <= #{endTime}
and re.room_id = #{roomId}
and rooms.name like concat ('%',#{roomName},'%')
and u.username like concat ('%',#{username},'%')
order by re.created_at desc

SELECT re.id, re.user_id as userId, u.real_name as realName, u.phone, re.room_id as roomId, rooms.room_number as roomNumber, rooms.name as roomName, re.start_time as startTime, re.end_time as endTime, re.sign_start_time as signStartTime, re.sign_end_time as signEndTime FROM reservations re LEFT JOIN users u ON re.user_id = u.id LEFT JOIN rooms ON re.room_id = rooms.id
AND re.user_id = #{userId}
AND re.status = #{status}
AND re.start_time >= #{startTime}
AND re.end_time <= #{endTime}
AND re.room_id = #{roomId}
AND rooms.name LIKE CONCAT('%', #{roomName}, '%')
AND u.username LIKE CONCAT('%', #{username}, '%')
ORDER BY re.created_at DESC
